const message = $json.message;

if (!message) {
  return {
    ignore: true,
    isPrivate: false,
    isGroup: false,
    isTaxiCommand: false,
    reason: "No Telegram message"
  };
}

const text = String(message.text || "")
  .trim()
  .replace(/\s+/g, " ");

const command = text
  .split(/\s+/)[0]
  .split("@")[0]
  .toLowerCase();

const chatType = String(message.chat?.type || "");
const chatId = String(message.chat?.id || "");

const now = new Date();

const taxiDate = new Intl.DateTimeFormat("en-CA", {
  timeZone: "Europe/Kyiv",
  year: "numeric",
  month: "2-digit",
  day: "2-digit"
}).format(now);

const currentDateTime = new Intl.DateTimeFormat("sv-SE", {
  timeZone: "Europe/Kyiv",
  year: "numeric",
  month: "2-digit",
  day: "2-digit",
  hour: "2-digit",
  minute: "2-digit",
  second: "2-digit"
}).format(now);

const isPrivate = chatType === "private";

const isGroup =
  chatType === "group" ||
  chatType === "supergroup";

const isPlus = text === "+";
const isMinus = text === "-";

/*
  Поки ID групи ще не зафіксований,
  перевіряємо лише тип чату.

  Після тесту сюди вставимо ID групи TONY.
*/
const allowedGroupId = "";

const isAllowedGroup = allowedGroupId
  ? chatId === allowedGroupId
  : isGroup;

const isTaxiCommand =
  isAllowedGroup &&
  (isPlus || isMinus);

return {
  chatId,
  chatType,
  chatTitle: String(message.chat?.title || ""),
  messageId: message.message_id || null,

  telegramUserId: String(message.from?.id || ""),
  telegramUsername: String(message.from?.username || ""),
  telegramFirstName: String(message.from?.first_name || ""),

  text,
  command,

  isPrivate,
  isGroup,
  isAllowedGroup,

  isPlus,
  isMinus,
  isTaxiCommand,

  isStart: command === "/start",
  isRegister: command === "/register",

  taxiDate,
  taxiMarkedAt: currentDateTime,
  currentDateTime,

  ignore: false
};

const source =
  $("Normalize Registration Message").first().json;

const rows = $input.all()
  .map(item => item.json)
  .filter(row =>
    row &&
    Object.keys(row).length > 0 &&
    row.telegram_user_id
  );

const employee = rows.find(row =>
  String(row.telegram_user_id || "").trim() ===
  String(source.telegramUserId || "").trim()
);

const registrationStatus = String(
  employee?.registration_status || "not_started"
)
  .trim()
  .toLowerCase();

const registrationStep = String(
  employee?.registration_step || "not_started"
)
  .trim()
  .toLowerCase();

return [
  {
    json: {
      ...source,
      employeeFound: Boolean(employee),
      employee: employee || null,
      registrationStep,
      registrationStatus,
      employeeRegistered:
        registrationStatus === "completed"
    }
  }
];

const name = String($json.text || "")
  .trim()
  .replace(/\s+/g, " ");

const words = name.split(" ").filter(Boolean);

const forbiddenValues = [
  "+",
  "-",
  "/start",
  "/register"
];

const hasOnlyLetters =
  /^[A-Za-zА-Яа-яЁёІіЇїЄєҐґ'’ʼ-]+(?:\s+[A-Za-zА-Яа-яЁёІіЇїЄєҐґ'’ʼ-]+)+$/.test(name);

const nameValid =
  !$json.hasLocation &&
  name.length >= 3 &&
  name.length <= 100 &&
  words.length >= 2 &&
  hasOnlyLetters &&
  !forbiddenValues.includes(name.toLowerCase());

return {
  ...$json,
  enteredName: name,
  nameValid,
  validationDebug: {
    wordsCount: words.length,
    hasOnlyLetters,
    hasLocation: Boolean($json.hasLocation)
  }
};

const enteredAddress = String($json.text || "")
  .trim()
  .replace(/\s+/g, " ");

const forbiddenValues = [
  "",
  "+",
  "-",
  "/start",
  "/register"
];

const lowerAddress = enteredAddress.toLowerCase();

const addressTextValid =
  enteredAddress.length >= 5 &&
  enteredAddress.length <= 200 &&
  !forbiddenValues.includes(lowerAddress);

return {
  ...$json,
  enteredAddress,
  addressTextValid
};

const source =
  $("Prepare Text Address").first().json;

const result = $json.results?.[0] || null;

if (!result) {
  return {
    ...source,
    addressFound: false,
    addressError:
      $json.error_message ||
      $json.status ||
      "Address not found"
  };
}

const location = result.geometry?.location;

const resolvedAddress =
  String(result.formatted_address || "").trim();

const resolvedLatitude =
  location?.lat != null
    ? Number(location.lat)
    : null;

const resolvedLongitude =
  location?.lng != null
    ? Number(location.lng)
    : null;

const addressFound = Boolean(
  resolvedAddress &&
  Number.isFinite(resolvedLatitude) &&
  Number.isFinite(resolvedLongitude)
);

return {
  ...source,
  addressFound,
  resolvedAddress,
  resolvedLatitude,
  resolvedLongitude
};

